        Question(skill_id='verbal_reading', question_type='reading', difficulty=0.6, text_ar='What is the difference between the theories?', option_a='No difference', option_b='Greeks: eye sends rays; Ibn al-Haytham: light reflects to eye', option_c='Ibn al-Haytham: eye sends rays too', option_d='Greeks had no theory', correct_option='b', explanation_ar='The text compares: Greek (eye sends) vs Ibn al-Haytham (light reflects).', solution_steps_ar='["Identify Greek theory","Identify Ibn al-Haytham theory","Comparison matches option (b)"]', tags='main-idea', stage='peak', rating_clarity=5, rating_cognitive=4, rating_fairness=5, rating_distractors=5, rating_difficulty_align=4, rating_explanation=5, rating_discrimination=5, rating_overall=4.71, source_key='verbal_reading:0084'),
